/**
 * User Module Service Tests
 *
 * Unit tests for UserService covering:
 * - User CRUD operations (tenant-scoped)
 * - Profile management
 * - Role assignment and removal
 * - Status changes
 * - Password management
 *
 * @module modules/_core/user/__tests__/user.service.spec
 */

import { describe, it, expect, beforeEach, vi, type Mock } from 'vitest';
import { UserStatus } from '@prisma/client';

import { UserService } from '@/modules/_core/user/user.service';
import { AppException } from '@/core/exceptions/app.exception';
import type { AuthService } from '@/core/services/auth.service';
import type { EventService } from '@/core/services/event.service';

// -----------------------------------------------------------------------------
// Mock Factories
// -----------------------------------------------------------------------------

/**
 * Creates a mock UserRepository
 */
function createMockRepository() {
  return {
    findAllByOrganization: vi.fn(),
    findAllSummaries: vi.fn(),
    findById: vi.fn(),
    findByIdInOrganization: vi.fn(),
    findByIdWithRelations: vi.fn(),
    findByIdOrThrow: vi.fn(),
    findByEmail: vi.fn(),
    emailExists: vi.fn(),
    countByOrganization: vi.fn(),
    getUserRoles: vi.fn(),
    create: vi.fn(),
    update: vi.fn(),
    updateStatus: vi.fn(),
    assignRole: vi.fn(),
    removeRole: vi.fn(),
    hasRole: vi.fn(),
    hasRoleByName: vi.fn(),
    softDelete: vi.fn(),
    restore: vi.fn(),
  };
}

/**
 * Creates a mock AuthService
 */
function createMockAuthService(): {
  hashPassword: Mock;
  verifyPassword: Mock;
} {
  return {
    hashPassword: vi.fn(),
    verifyPassword: vi.fn(),
  };
}

/**
 * Creates a mock EventService
 */
function createMockEventService(): { emitCustom: Mock } {
  return {
    emitCustom: vi.fn(),
  };
}

/**
 * Creates a mock user for testing
 */
function createMockUser(overrides: Partial<{
  id: string;
  email: string;
  passwordHash: string;
  firstName: string;
  lastName: string;
  phone: string | null;
  avatar: string | null;
  organizationId: string | null;
  status: UserStatus;
  emailVerifiedAt: Date | null;
  lastLoginAt: Date | null;
  createdAt: Date;
  updatedAt: Date;
  deletedAt: Date | null;
}> = {}) {
  return {
    id: 'user_123',
    email: 'test@example.com',
    passwordHash: 'hashed_password',
    firstName: 'John',
    lastName: 'Doe',
    phone: '+905551234567',
    avatar: null,
    organizationId: 'org_123',
    status: UserStatus.ACTIVE,
    emailVerifiedAt: new Date(),
    lastLoginAt: null,
    createdAt: new Date(),
    updatedAt: new Date(),
    deletedAt: null,
    ...overrides,
  };
}

/**
 * Creates a mock user with relations for testing
 */
function createMockUserWithRelations(overrides: Partial<ReturnType<typeof createMockUser>> = {}) {
  return {
    ...createMockUser(overrides),
    organization: {
      id: 'org_123',
      name: 'Test Organization',
      slug: 'test-org',
    },
    userRoles: [
      {
        role: {
          id: 'role_1',
          name: 'owner',
          displayName: 'Owner',
          scope: 'ORGANIZATION',
        },
      },
    ],
    _count: {
      userRoles: 1,
      sessions: 2,
    },
  };
}

// -----------------------------------------------------------------------------
// Test Suite
// -----------------------------------------------------------------------------

describe('UserService', () => {
  let service: UserService;
  let mockRepository: ReturnType<typeof createMockRepository>;
  let mockAuthService: ReturnType<typeof createMockAuthService>;
  let mockEventService: ReturnType<typeof createMockEventService>;

  beforeEach(() => {
    mockRepository = createMockRepository();
    mockAuthService = createMockAuthService();
    mockEventService = createMockEventService();

    service = new UserService(
      mockRepository as unknown as Parameters<typeof UserService['prototype']['constructor']>[0],
      mockAuthService as unknown as AuthService,
      mockEventService as unknown as EventService
    );
  });

  // ---------------------------------------------------------------------------
  // List Operations Tests
  // ---------------------------------------------------------------------------

  describe('list', () => {
    it('should return paginated users for organization', async () => {
      // Arrange
      const mockUsers = [createMockUser(), createMockUser({ id: 'user_456' })];
      mockRepository.findAllByOrganization.mockResolvedValue({
        data: mockUsers,
        meta: { page: 1, perPage: 20, total: 2, totalPages: 1 },
      });

      // Act
      const result = await service.list('org_123', { page: 1, perPage: 20 });

      // Assert
      expect(result.data).toHaveLength(2);
      expect(result.meta.total).toBe(2);
      expect(mockRepository.findAllByOrganization).toHaveBeenCalledWith(
        'org_123',
        expect.objectContaining({ page: 1, perPage: 20 })
      );
    });

    it('should exclude password hash from returned users', async () => {
      // Arrange
      const mockUsers = [createMockUser()];
      mockRepository.findAllByOrganization.mockResolvedValue({
        data: mockUsers,
        meta: { page: 1, perPage: 20, total: 1, totalPages: 1 },
      });

      // Act
      const result = await service.list('org_123', {});

      // Assert
      expect(result.data[0]).not.toHaveProperty('passwordHash');
    });
  });

  describe('listSummaries', () => {
    it('should return user summaries', async () => {
      // Arrange
      const mockSummaries = [
        { id: 'user_1', email: 'user1@test.com', fullName: 'User One' },
        { id: 'user_2', email: 'user2@test.com', fullName: 'User Two' },
      ];
      mockRepository.findAllSummaries.mockResolvedValue(mockSummaries);

      // Act
      const result = await service.listSummaries('org_123');

      // Assert
      expect(result).toHaveLength(2);
      expect(mockRepository.findAllSummaries).toHaveBeenCalledWith('org_123', undefined);
    });
  });

  // ---------------------------------------------------------------------------
  // Read Operations Tests
  // ---------------------------------------------------------------------------

  describe('getById', () => {
    it('should return safe user by ID', async () => {
      // Arrange
      const mockUser = createMockUser();
      mockRepository.findById.mockResolvedValue(mockUser);

      // Act
      const result = await service.getById('user_123');

      // Assert
      expect(result).not.toBeNull();
      expect(result).not.toHaveProperty('passwordHash');
      expect(mockRepository.findById).toHaveBeenCalledWith('user_123');
    });

    it('should return null when user not found', async () => {
      // Arrange
      mockRepository.findById.mockResolvedValue(null);

      // Act
      const result = await service.getById('nonexistent');

      // Assert
      expect(result).toBeNull();
    });
  });

  describe('getByIdInOrganization', () => {
    it('should return user within organization', async () => {
      // Arrange
      const mockUser = createMockUser();
      mockRepository.findByIdInOrganization.mockResolvedValue(mockUser);

      // Act
      const result = await service.getByIdInOrganization('user_123', 'org_123');

      // Assert
      expect(result).not.toBeNull();
      expect(mockRepository.findByIdInOrganization).toHaveBeenCalledWith('user_123', 'org_123');
    });

    it('should return null for user not in organization', async () => {
      // Arrange
      mockRepository.findByIdInOrganization.mockResolvedValue(null);

      // Act
      const result = await service.getByIdInOrganization('user_123', 'other_org');

      // Assert
      expect(result).toBeNull();
    });
  });

  describe('getByIdWithRelations', () => {
    it('should return user with relations', async () => {
      // Arrange
      const mockUser = createMockUserWithRelations();
      mockRepository.findByIdWithRelations.mockResolvedValue(mockUser);

      // Act
      const result = await service.getByIdWithRelations('user_123');

      // Assert
      expect(result).toHaveProperty('organization');
      expect(result).toHaveProperty('userRoles');
    });

    it('should throw error when user not found', async () => {
      // Arrange
      mockRepository.findByIdWithRelations.mockResolvedValue(null);

      // Act & Assert
      await expect(service.getByIdWithRelations('nonexistent')).rejects.toThrow(AppException);
    });
  });

  describe('getProfile', () => {
    it('should return user profile with roles', async () => {
      // Arrange
      const mockUser = createMockUserWithRelations();
      mockRepository.findByIdWithRelations.mockResolvedValue(mockUser);

      // Act
      const result = await service.getProfile('user_123');

      // Assert
      expect(result).toHaveProperty('roles');
      expect(result.roles).toContain('owner');
    });

    it('should throw error when user not found', async () => {
      // Arrange
      mockRepository.findByIdWithRelations.mockResolvedValue(null);

      // Act & Assert
      await expect(service.getProfile('nonexistent')).rejects.toThrow(AppException);
    });
  });

  describe('getRoles', () => {
    it('should return user roles', async () => {
      // Arrange
      const mockRoles = [
        { roleId: 'role_1', roleName: 'owner', roleDisplayName: 'Owner' },
      ];
      mockRepository.getUserRoles.mockResolvedValue(mockRoles);

      // Act
      const result = await service.getRoles('user_123');

      // Assert
      expect(result).toHaveLength(1);
      expect(result[0]?.roleName).toBe('owner');
    });
  });

  // ---------------------------------------------------------------------------
  // Create Operations Tests
  // ---------------------------------------------------------------------------

  describe('create', () => {
    const validCreateData = {
      email: 'newuser@example.com',
      password: 'SecurePass123!',
      firstName: 'Jane',
      lastName: 'Smith',
      phone: '+905551234567',
    };

    it('should create user successfully', async () => {
      // Arrange
      mockRepository.emailExists.mockResolvedValue(false);
      mockAuthService.hashPassword.mockResolvedValue('hashed_new_password');
      const createdUser = createMockUser({
        id: 'user_new',
        email: validCreateData.email,
        firstName: validCreateData.firstName,
        lastName: validCreateData.lastName,
      });
      mockRepository.create.mockResolvedValue(createdUser);
      mockEventService.emitCustom.mockResolvedValue(undefined);

      // Act
      const result = await service.create('org_123', validCreateData);

      // Assert
      expect(result.user).toBeDefined();
      expect(result.user).not.toHaveProperty('passwordHash');
      expect(result.message).toContain('successfully');
      expect(mockAuthService.hashPassword).toHaveBeenCalledWith(validCreateData.password);
      expect(mockRepository.create).toHaveBeenCalledWith(
        expect.objectContaining({
          email: validCreateData.email,
          passwordHash: 'hashed_new_password',
          organizationId: 'org_123',
        })
      );
      expect(mockEventService.emitCustom).toHaveBeenCalledWith(
        'user.created',
        expect.objectContaining({
          userId: createdUser.id,
          email: createdUser.email,
        })
      );
    });

    it('should throw error when email already exists', async () => {
      // Arrange
      mockRepository.emailExists.mockResolvedValue(true);

      // Act & Assert
      await expect(service.create('org_123', validCreateData)).rejects.toThrow(AppException);

      expect(mockRepository.create).not.toHaveBeenCalled();
    });

    it('should assign roles when provided', async () => {
      // Arrange
      mockRepository.emailExists.mockResolvedValue(false);
      mockAuthService.hashPassword.mockResolvedValue('hashed_password');
      mockRepository.create.mockResolvedValue(createMockUser({ id: 'user_new' }));
      mockRepository.assignRole.mockResolvedValue(true);
      mockEventService.emitCustom.mockResolvedValue(undefined);

      // Act
      await service.create('org_123', { ...validCreateData, roleIds: ['role_1', 'role_2'] });

      // Assert
      expect(mockRepository.assignRole).toHaveBeenCalledTimes(2);
    });

    it('should create user with INVITED status when sendInvite is true', async () => {
      // Arrange
      mockRepository.emailExists.mockResolvedValue(false);
      mockAuthService.hashPassword.mockResolvedValue('hashed_password');
      mockRepository.create.mockResolvedValue(createMockUser({ status: UserStatus.INVITED }));
      mockEventService.emitCustom.mockResolvedValue(undefined);

      // Act
      const result = await service.create('org_123', { ...validCreateData, sendInvite: true });

      // Assert
      expect(mockRepository.create).toHaveBeenCalledWith(
        expect.objectContaining({ status: UserStatus.INVITED })
      );
      expect(result.inviteSent).toBe(true);
    });
  });

  // ---------------------------------------------------------------------------
  // Update Operations Tests
  // ---------------------------------------------------------------------------

  describe('update', () => {
    const validUpdateData = {
      firstName: 'Updated',
      lastName: 'Name',
    };

    it('should update user successfully', async () => {
      // Arrange
      const currentUser = createMockUser();
      const updatedUser = createMockUser({ firstName: 'Updated', lastName: 'Name' });
      mockRepository.findByIdInOrganization.mockResolvedValue(currentUser);
      mockRepository.update.mockResolvedValue(updatedUser);
      mockEventService.emitCustom.mockResolvedValue(undefined);

      // Act
      const result = await service.update('user_123', 'org_123', validUpdateData);

      // Assert
      expect(result.user.firstName).toBe('Updated');
      expect(result.user).not.toHaveProperty('passwordHash');
      expect(mockEventService.emitCustom).toHaveBeenCalledWith(
        'user.updated',
        expect.objectContaining({ userId: 'user_123' })
      );
    });

    it('should throw error when user not found in organization', async () => {
      // Arrange
      mockRepository.findByIdInOrganization.mockResolvedValue(null);

      // Act & Assert
      await expect(
        service.update('user_123', 'org_123', validUpdateData)
      ).rejects.toThrow(AppException);
    });
  });

  describe('updateProfile', () => {
    it('should update user profile successfully', async () => {
      // Arrange
      const currentUser = createMockUser();
      const updatedUser = createMockUser({ firstName: 'Updated' });
      mockRepository.findByIdOrThrow.mockResolvedValue(currentUser);
      mockRepository.update.mockResolvedValue(updatedUser);
      mockRepository.findByIdWithRelations.mockResolvedValue(createMockUserWithRelations());
      mockEventService.emitCustom.mockResolvedValue(undefined);

      // Act
      const result = await service.updateProfile('user_123', { firstName: 'Updated' });

      // Assert
      expect(result.profile).toBeDefined();
      expect(mockEventService.emitCustom).toHaveBeenCalledWith(
        'user.profile.updated',
        expect.any(Object)
      );
    });
  });

  describe('changePassword', () => {
    const validPasswordData = {
      currentPassword: 'OldPass123!',
      newPassword: 'NewPass456!',
    };

    it('should change password successfully', async () => {
      // Arrange
      const mockUser = createMockUser();
      mockRepository.findByIdOrThrow.mockResolvedValue(mockUser);
      mockAuthService.verifyPassword.mockResolvedValue(true);
      mockAuthService.hashPassword.mockResolvedValue('new_hashed_password');
      mockRepository.update.mockResolvedValue(mockUser);
      mockEventService.emitCustom.mockResolvedValue(undefined);

      // Act
      const result = await service.changePassword('user_123', validPasswordData);

      // Assert
      expect(result.message).toContain('successfully');
      expect(mockAuthService.verifyPassword).toHaveBeenCalledWith(
        validPasswordData.currentPassword,
        mockUser.passwordHash
      );
      expect(mockAuthService.hashPassword).toHaveBeenCalledWith(validPasswordData.newPassword);
    });

    it('should throw error when current password is incorrect', async () => {
      // Arrange
      const mockUser = createMockUser();
      mockRepository.findByIdOrThrow.mockResolvedValue(mockUser);
      mockAuthService.verifyPassword.mockResolvedValue(false);

      // Act & Assert
      await expect(
        service.changePassword('user_123', validPasswordData)
      ).rejects.toThrow(AppException);
    });
  });

  describe('changeStatus', () => {
    it('should change status successfully', async () => {
      // Arrange
      const currentUser = createMockUser({ status: UserStatus.ACTIVE });
      const updatedUser = createMockUser({ status: UserStatus.SUSPENDED });
      mockRepository.findByIdInOrganization.mockResolvedValue(currentUser);
      mockRepository.updateStatus.mockResolvedValue(updatedUser);
      mockEventService.emitCustom.mockResolvedValue(undefined);

      // Act
      const result = await service.changeStatus('user_123', 'org_123', {
        status: UserStatus.SUSPENDED,
        reason: 'Policy violation',
      });

      // Assert
      expect(result.user.status).toBe(UserStatus.SUSPENDED);
      expect(result.previousStatus).toBe(UserStatus.ACTIVE);
      expect(mockEventService.emitCustom).toHaveBeenCalledWith(
        'user.status.changed',
        expect.objectContaining({
          previousStatus: UserStatus.ACTIVE,
          newStatus: UserStatus.SUSPENDED,
        })
      );
    });

    it('should return unchanged when status is same', async () => {
      // Arrange
      const currentUser = createMockUser({ status: UserStatus.ACTIVE });
      mockRepository.findByIdInOrganization.mockResolvedValue(currentUser);

      // Act
      const result = await service.changeStatus('user_123', 'org_123', {
        status: UserStatus.ACTIVE,
      });

      // Assert
      expect(result.message).toContain('unchanged');
      expect(mockRepository.updateStatus).not.toHaveBeenCalled();
    });
  });

  // ---------------------------------------------------------------------------
  // Role Operations Tests
  // ---------------------------------------------------------------------------

  describe('assignRole', () => {
    it('should assign role successfully', async () => {
      // Arrange
      const mockUser = createMockUser();
      mockRepository.findByIdInOrganization.mockResolvedValue(mockUser);
      mockRepository.assignRole.mockResolvedValue(true);
      mockEventService.emitCustom.mockResolvedValue(undefined);

      // Act
      const result = await service.assignRole('user_123', 'org_123', { roleId: 'role_1' });

      // Assert
      expect(result.userId).toBe('user_123');
      expect(result.roleId).toBe('role_1');
      expect(mockEventService.emitCustom).toHaveBeenCalledWith(
        'user.role.assigned',
        expect.any(Object)
      );
    });

    it('should throw error when role already assigned', async () => {
      // Arrange
      const mockUser = createMockUser();
      mockRepository.findByIdInOrganization.mockResolvedValue(mockUser);
      mockRepository.assignRole.mockResolvedValue(false);

      // Act & Assert
      await expect(
        service.assignRole('user_123', 'org_123', { roleId: 'role_1' })
      ).rejects.toThrow(AppException);
    });
  });

  describe('removeRole', () => {
    it('should remove role successfully', async () => {
      // Arrange
      const mockUser = createMockUser();
      mockRepository.findByIdInOrganization.mockResolvedValue(mockUser);
      mockRepository.removeRole.mockResolvedValue(true);
      mockEventService.emitCustom.mockResolvedValue(undefined);

      // Act
      const result = await service.removeRole('user_123', 'org_123', { roleId: 'role_1' });

      // Assert
      expect(result.userId).toBe('user_123');
      expect(result.roleId).toBe('role_1');
      expect(mockEventService.emitCustom).toHaveBeenCalledWith(
        'user.role.removed',
        expect.any(Object)
      );
    });

    it('should throw error when role not assigned', async () => {
      // Arrange
      const mockUser = createMockUser();
      mockRepository.findByIdInOrganization.mockResolvedValue(mockUser);
      mockRepository.removeRole.mockResolvedValue(false);

      // Act & Assert
      await expect(
        service.removeRole('user_123', 'org_123', { roleId: 'role_1' })
      ).rejects.toThrow(AppException);
    });
  });

  // ---------------------------------------------------------------------------
  // Delete Operations Tests
  // ---------------------------------------------------------------------------

  describe('delete', () => {
    it('should soft delete user successfully', async () => {
      // Arrange
      const mockUser = createMockUser();
      mockRepository.findByIdInOrganization.mockResolvedValue(mockUser);
      mockRepository.softDelete.mockResolvedValue(undefined);
      mockEventService.emitCustom.mockResolvedValue(undefined);

      // Act
      await service.delete('user_123', 'org_123');

      // Assert
      expect(mockRepository.softDelete).toHaveBeenCalledWith('user_123');
      expect(mockEventService.emitCustom).toHaveBeenCalledWith(
        'user.deleted',
        expect.objectContaining({ userId: 'user_123' })
      );
    });

    it('should throw error when user not in organization', async () => {
      // Arrange
      mockRepository.findByIdInOrganization.mockResolvedValue(null);

      // Act & Assert
      await expect(service.delete('user_123', 'org_123')).rejects.toThrow(AppException);
    });
  });

  describe('restore', () => {
    it('should restore user successfully', async () => {
      // Arrange
      const restoredUser = createMockUser();
      mockRepository.restore.mockResolvedValue(restoredUser);
      mockEventService.emitCustom.mockResolvedValue(undefined);

      // Act
      const result = await service.restore('user_123');

      // Assert
      expect(result).not.toHaveProperty('passwordHash');
      expect(mockEventService.emitCustom).toHaveBeenCalledWith(
        'user.restored',
        expect.any(Object)
      );
    });
  });

  // ---------------------------------------------------------------------------
  // Validation Operations Tests
  // ---------------------------------------------------------------------------

  describe('isEmailAvailable', () => {
    it('should return true when email is available', async () => {
      // Arrange
      mockRepository.emailExists.mockResolvedValue(false);

      // Act
      const result = await service.isEmailAvailable('new@email.com');

      // Assert
      expect(result).toBe(true);
    });

    it('should return false when email exists', async () => {
      // Arrange
      mockRepository.emailExists.mockResolvedValue(true);

      // Act
      const result = await service.isEmailAvailable('existing@email.com');

      // Assert
      expect(result).toBe(false);
    });
  });

  describe('hasRole', () => {
    it('should return true when user has role', async () => {
      // Arrange
      mockRepository.hasRole.mockResolvedValue(true);

      // Act
      const result = await service.hasRole('user_123', 'role_1');

      // Assert
      expect(result).toBe(true);
    });
  });

  describe('hasRoleByName', () => {
    it('should return true when user has role by name', async () => {
      // Arrange
      mockRepository.hasRoleByName.mockResolvedValue(true);

      // Act
      const result = await service.hasRoleByName('user_123', 'owner');

      // Assert
      expect(result).toBe(true);
    });
  });

  // ---------------------------------------------------------------------------
  // Invite Operations Tests
  // ---------------------------------------------------------------------------

  describe('invite', () => {
    const validInviteData = {
      email: 'invite@example.com',
      firstName: 'Invited',
      lastName: 'User',
      roleId: 'role_1',
    };

    it('should invite user successfully', async () => {
      // Arrange
      mockRepository.emailExists.mockResolvedValue(false);
      mockAuthService.hashPassword.mockResolvedValue('temp_hashed_password');
      const createdUser = createMockUser({
        id: 'user_new',
        email: validInviteData.email,
        status: UserStatus.INVITED,
      });
      mockRepository.create.mockResolvedValue(createdUser);
      mockRepository.assignRole.mockResolvedValue(true);
      mockEventService.emitCustom.mockResolvedValue(undefined);

      // Act
      const result = await service.invite('org_123', validInviteData);

      // Assert
      expect(result.user).toBeDefined();
      expect(result.message).toContain('Invitation');
      expect(mockRepository.create).toHaveBeenCalledWith(
        expect.objectContaining({
          email: validInviteData.email,
          status: UserStatus.INVITED,
        })
      );
      expect(mockRepository.assignRole).toHaveBeenCalled();
      expect(mockEventService.emitCustom).toHaveBeenCalledWith(
        'user.invited',
        expect.any(Object)
      );
    });

    it('should throw error when email already exists', async () => {
      // Arrange
      mockRepository.emailExists.mockResolvedValue(true);

      // Act & Assert
      await expect(service.invite('org_123', validInviteData)).rejects.toThrow(AppException);
    });
  });
});
